import header from '../../css/header.module.css';

const Header = () => {
  return (
    <header className={header.header}>
        <h1><span className={header.h1}>Dash</span>board</h1>
        
        {/* 2. Correct Class Name Syntax */}
        <div className={styles.searh_bar}> 
            <input type="text" placeholder="Search your task here..."/>
            <button><img src="/images/icons/search.svg" alt="search"/></button>
        </div>
        
        <button><img src="/images/icons/notification.svg" alt="notification"/></button>
        <button><img src="/images/icons/calender.svg" alt="calendar"/></button>

        <div className="date"> 
            <label>Tuesday</label>
            <label><span className={styles['blue-text']}>20/06/2023</span></label>
        </div>
    </header>
  );
};

export default Header;
